useEffect(() => {
  fetch("https://upload.wikimedia.org/wikipedia/en/a/a9/Example.jpg").then(
    (resp) => {
      if (resp.ok) {
        resp.blob().then((blob) => {

          const imageType = blob.type;

          // we support more image types, this is just a quick hack for TS
          if (imageType !== "image/jpeg" && imageType !== "image/png") {
            return;
          }

          getDataURL(blob).then((dataURL) => {
            const fileId = "random-file-id" as FileId;

            const imageElement: ExcalidrawImageElement = {
              // image attributes
              // ------------------
              type: "image",
              id: "random-image-element-id",
              status: "saved",
              fileId,
              // generic attributes
              // ------------------
              version: 2,
              versionNonce: Date.now(),
              x: 200,
