              roughness: 1,
              opacity: 100,
              groupIds: [],
              strokeColor: "#000000",
              backgroundColor: "transparent",
              seed: Date.now(),
              roundness: null,
              angle: 0,
              frameId: null,
              boundElements: null,
              updated: Date.now(),
              locked: false,
              link: null,
            };

            setInitialData({
              elements: [imageElement],
              files: {
                [fileId]: {
                  mimeType: imageType,
                  id: fileId,
                  dataURL,
                  created: Date.now(),
