I wanted to share an update regarding the automation of room access in Excalidraw. I've managed to solve the challenge by passing the room ID directly within the URL.

To facilitate this process in an Angular environment, here's a snippet of the Angular service I've used:

```
import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class IVGenerationService {

  constructor() { }

  // Generate a 22-character length IV based on a provided string
  generateIVFromSeed(seed: string): Promise<string> {
    // Hash the seed value using SHA-256
    async function sha256(message: string): Promise<string> {
      const msgBuffer = new TextEncoder().encode(message);
      const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    }

    // Get a 32-character hexadecimal hash
    async function getHashedValue(): Promise<string> {
      const hashedSeed = await sha256(seed);
      return hashedSeed.substring(0, 32); // Use the first 32 characters of the hash
    }

    // Convert the hexadecimal hash to a 22-character Base64 string
    async function convertToBase64(hash: string): Promise<string> {
      const binaryHash = hash.match(/.{1,2}/g).map(byte => parseInt(byte, 16));
      const iv = btoa(String.fromCharCode.apply(null, new Uint8Array(binaryHash)))
        .replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, ''); // Ensure URL safety
      return iv.substring(0, 22); // Use the first 22 characters of the encoded hash
    }

    // Generate and return the IV
    return getHashedValue().then(convertToBase64);
  }
}
```

