    "Content-Type": "application/json"
}

def create_diagram(prompt):
    # The request payload
    payload = {
        "model": "qwen3-vl:8b-instruct",
        "messages": [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": prompt}
         ],
         "temperature": 0.2
     }
    response = requests.post(url, headers=headers, json=payload)
    return response

def wireframe_to_code(post_data):
    # The request payload
    texts = post_data.get("texts")
    payload = {
        "model": "qwen3-vl:8b-instruct",
        "messages": [
            {"role": "system", "content": SYSTEM_PROMPT_WIREFRAME},
            {"role": "user", "content": [
                {"type": "text", "text": f"Readable Text: {texts}\n\n"},
                {"type": "image_url", "image_url": {"url": post_data.get("image")} }
            ] }
         ],
         "temperature": 0.2
     }
    response = requests.post(url, headers=headers, json=payload)
    return response

class SimpleHTTPRequestHandler(BaseHTTPRequestHandler):
    def do_POST(self):

        if self.path == '/v1/ai/text-to-diagram/generate':
            self.handle_generate_diagram()
        elif self.path == '/v1/ai/diagram-to-code/generate':
            self.handle_generate_code()
        else:
            self.handle_default_post()        

    def handle_generate_diagram(self):
        content_length = int(self.headers.get("Content-Length", 0))
        post_data = self.rfile.read(content_length).decode("utf-8")

        self.send_response(200)
        self.send_header("Content-Type", "text/plain")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        print(post_data)
        post_data_json = json.loads(post_data)

        if post_data_json.get("prompt"): 
            response = create_diagram(post_data_json.get("prompt"))
            response_text = strip_markdown_code(response.json()["choices"][0]["message"]["content"])
            response_message = {
                "generatedResponse": response_text
            }
            self.wfile.write(json.dumps(response_message, indent=2).encode("utf-8"))
        else:
            self.wfile.write("Error: No prompt provided.".encode("utf-8")) 

    def handle_generate_code(self):
        content_length = int(self.headers.get("Content-Length", 0))
        post_data = self.rfile.read(content_length).decode("utf-8")

        self.send_response(200)
        self.send_header("Content-Type", "text/plain")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()

        post_data_json = json.loads(post_data)

        if post_data_json.get("prompt") is None:
            response_text = wireframe_to_code(post_data_json)
            #response_text = "<html><body style=\"margin: 0; text-align: center\">Error: No prompt provided.</body></html>"
            response_message = {
                "html": response_text.json()["choices"][0]["message"]["content"]
            }
            self.wfile.write(json.dumps(response_message, indent=2).encode("utf-8"))
        else:
            self.wfile.write("Error: No prompt provided.".encode("utf-8"))   

def run(server_class=HTTPServer, handler_class=SimpleHTTPRequestHandler, port=8080):
    server_address = ("", port)
    httpd = server_class(server_address, handler_class)
    print(f"Server started on port {port}...")
    try:
        httpd.serve_forever()
    except KeyboardInterrupt:
        print("\nServer wird beendet...")
        httpd.shutdown()


if __name__ == "__main__":
    run()
