```
import React, { useState } from 'react';
import { Excalidraw, convertToExcalidrawElements } from '@excalidraw/excalidraw';
import { ArrowRight } from 'lucide-react';
import './IdeationCardCanvas.css';

export default function IdeationCardCanvas({ selectedCard }) {
    const [excalidrawAPI, setExcalidrawAPI] = useState(null);

    const addTemplateToCanvas = async () => {
        if (!selectedCard?.icon_url || !excalidrawAPI) {
            return;
        }

        try {
            // Fetch the image
            const response = await fetch(selectedCard.icon_url);
            const imageBlob = await response.blob();

            // Convert blob to base64
            const reader = new FileReader();
            reader.readAsDataURL(imageBlob);

            reader.onload = () => {
                const fileId = `file_${Date.now()}`;
                const dataURL = reader.result;

                // First, add the file to Excalidraw
                excalidrawAPI.addFiles([
                    {
                        id: fileId,
                        dataURL,
                        mimeType: imageBlob.type,
                    }
                ]);

                // Create a temporary Image object to get dimensions
                const img = new Image();
                img.src = dataURL;

                img.onload = () => {
                    // Scale image dimensions
                    const scaledWidth = img.width * 0.5;
                    const scaledHeight = img.height * 0.5;

                    // Calculate center positions
                    const textWidth = 400;
                    const imageX = 280 - (scaledWidth / 2);
                    const textX = 280 - (textWidth / 2);

                    // Create image element
                    const imageElement = {
                        type: "image",
                        id: `image_${Date.now()}`,
                        fileId,
                        x: imageX,
                        y: 80,
                        version: 1,
                        width: scaledWidth,
                        height: scaledHeight,
                        scale: [1, 1],
                        isDeleted: false,
                        fillStyle: "hachure",
                        strokeWidth: 1,
                        strokeStyle: "solid",
                        roughness: 1,
                        opacity: 100,
                        strokeColor: "#000000",
                        backgroundColor: 'transparent',
                        angle: 0,
                        groupIds: [],
                    };

                    // Create text element
                    const textElement = {
                        type: "text",
                        id: `text_${Date.now()}`,
                        x: textX,
                        y: imageElement.y + imageElement.height + 20,
                        width: textWidth,
                        height: 100,
                        text: selectedCard.title,
                        textAlign: "center",
                        strokeColor: "#54A4FC",
                        fontSize: 48,
                        fontFamily: "Allerta",
                        verticalAlign: "top",
                        baseline: 18,
                    };

                    // Update the scene with both elements
                    excalidrawAPI.updateScene({
                        elements: [
                            ...excalidrawAPI.getSceneElementsIncludingDeleted(),
                            imageElement,
                            ...convertToExcalidrawElements([textElement])
                        ],
                        appState: {
                            viewBackgroundColor: '#ffffff',
                            zoom: { value: 1 }
                        }
                    });
                };
            };
        } catch (error) {
            console.error("Failed to add image to canvas:", error);
        }
    };

    const clearCanvas = () => {
        if (excalidrawAPI) {
            excalidrawAPI.updateScene({
                elements: [],
                appState: {
                    viewBackgroundColor: '#ffffff',
                },
            });
        }
    };

    return (
        <div className="ideation-card-canvas">
            <div className="canvas-container">
                <button className="create-button" onClick={addTemplateToCanvas}>
                    <ArrowRight size={48} />
                    Create
                </button>
                <div className="canvas">
                    <Excalidraw
                        excalidrawAPI={setExcalidrawAPI}
                    />
                </div>
            </div>
            <div className="actions">
                <button className="save-button">Save</button>
                <button className="clear-button" onClick={clearCanvas}>Clear</button>
            </div>
        </div>
    );
}
```

