I have done it with a workaround:

1. Add a custom button that sets the active tool to arrow and sets a custom state to know that I am drawing a custom arrow
2. I update the scene with my custom config for color and end start/end arrow type
3. Then I handle the pointer down and the pointer update event
4. If the pointer is up I update the current arrow with my needed configuration:


The important note is that the updateArrow function has to be called async, so that the bindings are set.
Here a little code snippet:

```
type PointerPayload = {
    pointer: {
      x: number;
      y: number;
      tool: "pointer" | "laser";
    };
    button: "down" | "up";
    pointersMap: Gesture["pointers"];
  };

  type CustomArrowType = 'custom-arrow';

  type CustomArrowState = {
    id?: string,
    arrowType: CustomArrowType,
    hasStarted: boolean;
  }

  export function Excalidraw() {
    const [excalidrawAPI, setExcalidrawAPI] = useState<ExcalidrawImperativeAPI>();
    const [arrowState, setArrowState] = useState<CustomArrowState | undefined>();
    const [activeTool, setActiveTool] = useState<string | undefined>();

    const setActiveArrowTool = (arrowToolType: CustomArrowType) => {
      if (excalidrawAPI) {
        excalidrawAPI.setActiveTool({type: 'arrow'});
        setArrowState({ arrowType: arrowToolType, hasStarted: false});
        excalidrawAPI.updateScene({elements: null, appState: {currentItemStrokeColor: "#00FF22", currentItemEndArrowhead: 'triangle'}});
      }
    }

    const onChange = (elements: readonly ExcalidrawElement[], appState: AppState) => {
      const currentActiveTool = appState.activeTool.type === 'custom' ? appState.activeTool.customType : appState.activeTool.type;
      setActiveTool(currentActiveTool);

      if (appState.activeTool.type === 'arrow' && arrowState !== undefined) {
        if (appState.draggingElement && !arrowState?.id) {
          setArrowState((prevState) => prevState ? ({...prevState, id: appState.draggingElement?.id}) : undefined)
        }
      } else {
        setArrowState(undefined);
      }
    };

    const onPointerDown = (activeTool: AppState["activeTool"], pointerDownState: PointerDownState) => {
      if (arrowState) {
        setArrowState((prev) => prev ? ({...prev, hasStarted: true}) : undefined);
      }
    };

    const onPointerUpdate = (payload: PointerPayload) => {
      if (excalidrawAPI && payload.button === 'up' && arrowState?.hasStarted && arrowState.id) {
        const sceneElements = excalidrawAPI.getSceneElements();
        const arrowElement = sceneElements.find(x => x.id === arrowState.id) as ExcalidrawArrowElement;
        if (arrowElement) {
          setTimeout(() => updateArrow(arrowElement.id), 100);
        }
        setArrowState(undefined);
      }
    };

    const updateArrow = (arrowId: string) => {
      if (excalidrawAPI) {
        const sceneElements = excalidrawAPI.getSceneElements();
        const arrowElement = sceneElements.find(x => x.id === arrowId) as ExcalidrawArrowElement;

        if (arrowElement) {
          const startBinding = arrowElement.startBinding;
          const arrowText = convertToExcalidrawElements([
            {
              type: "text",
              text: "Update Status",
              strokeColor: '#FF0011',
              x: arrowElement.x + 100,
              y: arrowElement.y,
              angle: arrowElement.angle,
              locked: true,
              containerId: arrowElement.id,
            }
          ])[0];

          const boundElements = arrowElement.boundElements || [];
          const newArrow = {
            ...arrowElement,
            boundElements: [...boundElements, { id: arrowText.id, type: 'text' }],
            customData: { 'custom-key': 'customData' },
            locked: true,
          } as ExcalidrawLinearElement;
          excalidrawAPI.updateScene({ elements: [...sceneElements.filter(x => x !== arrowElement), newArrow, arrowText] })
        }
      }
    }

    return (
      <div style={{ height: '800px' }}>
        <button onClick={() => setActiveArrowTool('custom-arrow')}>Update Status</button>
        <Excalidraw
          excalidrawAPI={setExcalidrawAPI}
          onChange={onChange}
          onPointerDown={onPointerDown}
          onPointerUpdate={onPointerUpdate}
          renderTopRightUI={() => {
            return (
              <ExcalidrawToolbar />
            );
          }}
        >
        </Excalidraw>
      </div>
    );
  }
```

