export const convertTLArrow = (
    arrow: TLArrowShape,
    startBinding?: TLBinding,
    endBinding?: TLBinding,
    ancestors?: TLShape[]
) => {
    const { start, end, arrowheadStart, arrowheadEnd, size, dash, bend, text } = arrow.props

    const handlePoint = getHandlePoint(start, end, bend);

    const allPoints = [start, end]
    if (handlePoint) allPoints.push(handlePoint)
    const { bounding, width, height } = getBoundingBox(allPoints)

    const points = [];
    points.push(convertTLPoint(Vec.Sub(start, bounding)))
    if (handlePoint) points.push(convertTLPoint(Vec.Sub(handlePoint, bounding)))
    points.push(convertTLPoint(Vec.Sub(end, bounding)))

    const normalizedPoints = normalize(points)

    const elementSkeleton = {
        type: 'arrow' as const,
        width,
        height,
        points: normalizedPoints
    }

    return elementSkeleton;
}
