@Brikaa @mtolmacs  I like the reference to treating the dot as a circle instead, in order to improve performance. I think it'd be possible to calculate the `distance` from `lastPoint` to the center of the element, and compare `distance` with a `hitRadius`

```typescript
const eraserTest = (
  pathSegment: LineSegment<GlobalPoint>,
  element: ExcalidrawElement,
  elementsMap: ElementsMap,
): boolean => {
  const lastPoint = pathSegment[1];
  const boundBoxDiagonal = Math.hypot(element.width, element.height);
  const threshold = 1; // TBD
  const tolerance = element.strokeWidth * 2; // *2 works for the case of freedraw points
  if (
    shouldTestInside(element) &&
    isPointInElement(lastPoint, element, elementsMap)
  ) {
    return true;
  }

  // For freedraw-points, lines and arrows of shared endpoints
  if (boundBoxDiagonal < threshold) {
    const [cx, cy] = [element.x + element.width / 2, element.y + element.height / 2];
    const distance = Math.hypot(lastPoint[0] - cx, lastPoint[1] - cy);
    const hitRadius = Math.max(element.width, element.height) / 2 + tolerance;

    if (distance <= hitRadius) {
      return true;
    }
  }
```

